import{b as s,I as r,g as n,j as l}from"./chunks/framework.DUo3J_Qe.js";const t="/geo-ml/learning/concepts/ml-process.svg",i="/geo-ml/learning/concepts/ml-process1.png",a="/geo-ml/learning/concepts/ml-process2.png",o="/geo-ml/learning/concepts/ml-process5.png",d="/geo-ml/learning/concepts/ml-process4.png",u="/geo-ml/learning/concepts/ml-process3.png",v=JSON.parse('{"title":"Processus de machine learning supervisé","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/concepts/process.md","filePath":"fr/learning/concepts/process.md"}'),p={name:"fr/learning/concepts/process.md"};function c(m,e,g,h,b,f){return r(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="processus-de-machine-learning-supervise" tabindex="-1">Processus de machine learning supervisé <a class="header-anchor" href="#processus-de-machine-learning-supervise" aria-label="Permalink to &quot;Processus de machine learning supervisé&quot;">​</a></h1><p><img src="'+t+'" alt="Machine Learning Process"></p><ol><li><strong>Collecter et stocker des données</strong> du monde réel.</li><li><strong>Nettoyer et organiser les données</strong> pour les rendre exploitables.</li><li><strong>Effectuer une analyse exploratoire</strong> (statistiques, visualisations).</li><li><strong>Créer un produit de données</strong> avec le machine learning : <ul><li><strong>Supervisé</strong> : prédire un résultat futur.</li><li><strong>Non supervisé</strong> : découvrir des patterns dans les données.</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Pour le machine learning, nous utiliserons principalement la bibliothèque python <code>scikit-learn</code></p></div><div class="info custom-block"><p class="custom-block-title">👉 Exemple : prédiction du prix d’une maison</p><ul><li><strong>Caractéristiques (features, X)</strong> : superficie, nombre de chambres, nombre de salles de bain, etc.</li><li><strong>Label (étiquette, Y)</strong> : prix de vente de la maison.</li></ul><p><strong>But :</strong> Utiliser les données historiques étiquetées pour prédire le prix d’une nouvelle maison.</p><p>Ce processus illustre parfaitement la définition de l’apprentissage supervisé : <strong>prédire un résultat à partir de données historiques et étiquetées</strong>.</p></div><h2 id="etapes-cles-de-l-apprentissage-supervise" tabindex="-1">Étapes clés de l’apprentissage supervisé <a class="header-anchor" href="#etapes-cles-de-l-apprentissage-supervise" aria-label="Permalink to &quot;Étapes clés de l’apprentissage supervisé&quot;">​</a></h2><h3 id="_1-separer-les-donnees-en-features-labels" tabindex="-1">1. Séparer les données en features &amp; labels <a class="header-anchor" href="#_1-separer-les-donnees-en-features-labels" aria-label="Permalink to &quot;1. Séparer les données en features &amp; labels&quot;">​</a></h3><p><img src="'+i+'" alt="Machine Learning Process"></p><ul><li><code>X</code> : caractéristiques connues de la maison.</li><li><code>Y</code> : label à prédire (prix de vente).</li></ul><h3 id="_2-diviser-les-donnees-en-ensembles-d-entrainement-et-de-tests" tabindex="-1">2. Diviser les données en ensembles d’entraînement et de tests <a class="header-anchor" href="#_2-diviser-les-donnees-en-ensembles-d-entrainement-et-de-tests" aria-label="Permalink to &quot;2. Diviser les données en ensembles d’entraînement et de tests&quot;">​</a></h3><p><img src="'+a+'" alt="Machine Learning Process"></p><ul><li><strong>Training set (entraînement)</strong> : 70 % des données pour apprendre les relations entre X et Y.</li><li><strong>Test set (tests)</strong> : 30 % des données pour évaluer les performances du modèle sur des données <strong>jamais vues</strong>.</li></ul><div class="tip custom-block"><p class="custom-block-title">Pourquoi ?</p><ul><li>On ne peut pas évaluer le modèle sur les données utilisées pour l’entraînement, car il pourrait simplement les mémoriser.</li><li>Les données de test permettent une <strong>évaluation honnête et équitable</strong>.</li></ul></div><h3 id="_3-entrainer-le-modele" tabindex="-1">3. Entraîner le modèle <a class="header-anchor" href="#_3-entrainer-le-modele" aria-label="Permalink to &quot;3. Entraîner le modèle&quot;">​</a></h3><ul><li>Le modèle apprend à partir des données d’entraînement (<code>X_train</code>, <code>Y_train</code>).</li><li>Il détermine comment les features influencent le label.</li></ul><h3 id="_4-tester-le-modele" tabindex="-1">4. Tester le modèle <a class="header-anchor" href="#_4-tester-le-modele" aria-label="Permalink to &quot;4. Tester le modèle&quot;">​</a></h3><ul><li>Le modèle reçoit uniquement les features de test (<code>X_test</code>) et fait des prédictions.</li><li>On compare ensuite les prédictions aux labels réels (<code>Y_test</code>).</li></ul><h3 id="_5-ajuster-les-hyperparametres" tabindex="-1">5. Ajuster les hyperparamètres <a class="header-anchor" href="#_5-ajuster-les-hyperparametres" aria-label="Permalink to &quot;5. Ajuster les hyperparamètres&quot;">​</a></h3><p><img src="'+o+'" alt="Machine Learning Process"></p><ul><li>Si les performances sont insuffisantes, on ajuste les paramètres du modèle.</li><li>On répète l’entraînement et le test jusqu’à obtenir un modèle satisfaisant.</li></ul><h2 id="recapitulatif-du-flux-de-travail" tabindex="-1">Récapitulatif du flux de travail <a class="header-anchor" href="#recapitulatif-du-flux-de-travail" aria-label="Permalink to &quot;Récapitulatif du flux de travail&quot;">​</a></h2><p><img src="'+d+'" alt="Machine Learning Process"></p><ol><li>Collecter et nettoyer les données.</li><li>Identifier les features (X) et le label (Y).</li><li>Séparer les données en ensembles d’entraînement et de tests.</li><li>Entraîner le modèle sur l’ensemble d’entraînement.</li><li>Évaluer le modèle sur l’ensemble de tests.</li><li>Ajuster les hyperparamètres si nécessaire et répéter.</li><li>Déployer le modèle pour prédire de nouvelles données ou créer un produit de données.</li></ol><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Le machine learning supervisé consiste à :</p><p><img src="'+u+'" alt="Machine Learning Process"></p><ul><li>Utiliser des <strong>données historiques et étiquetées</strong>.</li><li>Apprendre les relations entre features et labels.</li><li>Évaluer le modèle de manière équitable sur des données non vues.</li><li>Ajuster le modèle pour améliorer ses prédictions avant le déploiement.</li></ul>',27)])])}const q=s(p,[["render",c]]);export{v as __pageData,q as default};
